/**
 * MicroLayer - Detailed task card visualization
 *
 * Renders detailed task cards with labels at zoom > 2.0x (MICRO LOD level).
 *
 * PERFORMANCE OPTIMIZATIONS:
 * - Frustum culling: Only renders tasks visible in the viewport
 * - InstancedMesh for grid lines: Single draw call instead of ~251 meshes
 * - Lazy label rendering: Only labels for visible tasks
 * - InstancedMesh for row backgrounds: Single draw call instead of 50 meshes
 */

import { useMemo, useRef, useEffect } from 'react';
import { InstancedMesh, Object3D, Color, Vector3 } from 'three';
import { Html, Line } from '@react-three/drei';
import { useThree } from '@react-three/fiber';
import type { TaskRender } from '../../data/types';
import { DEFAULT_VIEW_CONFIG } from '../../data/types';
import type { ViewportBounds } from '../InfiniteCanvas';

interface MicroLayerProps {
  tasks: TaskRender[];
  trainCount: number;
  /** Opacity for LOD transitions (0-1). Default: 1 */
  opacity?: number;
  /** Viewport bounds for frustum culling */
  viewportBounds?: ViewportBounds;
  /** Currently hovered task ID for highlight effect */
  hoveredTaskId?: string | null;
  /** Currently selected task ID for selection highlight (F019) */
  selectedTaskId?: string | null;
  /** Currently keyboard-focused task ID for focus indicator (F021) */
  focusedTaskId?: string | null;
}

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

// Task card dimensions
const CARD_PADDING = 2;
const CARD_HEIGHT = pxPerTrain - CARD_PADDING * 2 - 2; // Slightly smaller for grid visibility

// Color mappings (matching MesoLayer)
const COLORS: Record<string, string> = {
  blue: '#3b82f6',
  orange: '#f59e0b',
  gray: '#9ca3af',
};
const CONFLICT_COLOR = '#ef4444';

// Grid colors
const GRID_COLOR_MAJOR = '#d1d5db'; // Gray-300
const GRID_COLOR_MINOR = '#e5e7eb'; // Gray-200

// Row background colors
const ROW_BG_EVEN = '#ffffff';
const ROW_BG_ODD = '#f8fafc';

/**
 * Filter tasks that are visible within the viewport bounds
 * This is the core of frustum culling for performance
 */
function filterVisibleTasks(tasks: TaskRender[], viewportBounds?: ViewportBounds): TaskRender[] {
  if (!viewportBounds) return tasks;

  // Add padding to viewport bounds (render slightly outside visible area for smooth panning)
  const padding = 100; // world units
  const minX = viewportBounds.minX - padding;
  const maxX = viewportBounds.maxX + padding;
  const minY = viewportBounds.minY - padding;
  const maxY = viewportBounds.maxY + padding;

  return tasks.filter((task) => {
    const taskStartX = task.startDay * pxPerDay;
    const taskEndX = taskStartX + task.duration * pxPerDay;
    const taskY = -task.trainIndex * pxPerTrain - pxPerTrain / 2;

    // Check if task overlaps with viewport
    const xOverlap = taskEndX >= minX && taskStartX <= maxX;
    const yOverlap = taskY + pxPerTrain / 2 >= minY && taskY - pxPerTrain / 2 <= maxY;

    return xOverlap && yOverlap;
  });
}

// Highlight color multiplier for hovered tasks
const HOVER_BRIGHTNESS = 1.3;

// Selection indicator color (distinct cyan/teal)
const SELECTION_COLOR = '#06b6d4'; // cyan-500

// Focus indicator color (F021 - keyboard focus)
const FOCUS_COLOR = '#8b5cf6'; // violet-500

/**
 * Brighten a color for hover effect
 */
function brightenColor(hexColor: string, factor: number): Color {
  const color = new Color(hexColor);
  color.r = Math.min(1, color.r * factor);
  color.g = Math.min(1, color.g * factor);

